  const windowMs = (
    Number.isFinite(options.windowMs) && options.windowMs > 0
      ? options.windowMs
      : 60_000    // default: 1 minute
  );

  const maxRequests = (
    Number.isFinite(options.maxRequests) && options.maxRequests > 0
      ? Math.floor(options.maxRequests)
      : 100
