  // ── Background cleanup ─────────────────────────────────────────────────────
  // Sweeps every 60 s and deletes entries for IPs whose entire timestamp list
  // has slid out of the current window.  This is a safety net; per-request
  // pruning is the primary mechanism.  Fixed at 60 s — not tied to windowMs —
  // so it remains predictable for very long window configurations.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [ip, timestamps] of store) {
      const fresh = timestamps.filter(t => t > cutoff);
      if (fresh.length === 0) {
        store.delete(ip);           // no activity in the last window — free it
      } else if (fresh.length !== timestamps.length) {
        store.set(ip, fresh);       // write back the trimmed list
