      const retryAfter = Math.max(1, Math.ceil(msUntilOldestExpires / 1000));

      res.setHeader('Retry-After', String(retryAfter));

      // Do not call next(). The request is terminated here.
      return res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter
      });
    }

    // Request is allowed.
    timestamps.push(now);
    requests.set(ip, timestamps);

    const remaining = Math.max(0, maxRequests - timestamps.length);

    // X-RateLimit-Reset reports the Unix epoch seconds when the oldest request
    // in the current window for this client will expire (i.e. when count drops by one).
    // This is the semantically correct value for a sliding window.
    const resetEpochSeconds = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.setHeader('X-RateLimit-Limit', String(maxRequests));
    res.setHeader('X-RateLimit-Remaining', String(remaining));
    res.setHeader('X-RateLimit-Reset', String(resetEpochSeconds));

    next();
  };

  /**
   * Stops the internal cleanup timer.
   * Call this when the rate limiter is no longer needed (tests, server shutdown, etc.)
   * so the interval does not prevent the Node.js process from exiting.
   */
  rateLimiter.close = () => {
    clearInterval(cleanupInterval);
  };

  // Non-enumerable internal handle exposed for testing / debugging only.
  // Consumers should not rely on this in production code.
  Object.defineProperty(rateLimiter, '_requestsStore', {
    value: requests,
    writable: false,
    enumerable: false,
    configurable: false
  });

  return rateLimiter;
}

